#include<bits/stdc++.h>
using namespace std;
long long ds[55][55];
int chang[55][55];
int tot=0;
int main()
{
	int n,m;
	scanf("%d%d",&n,&m);
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			scanf("%lld",&ds[i][j]);
		}
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			for(int k=1;k<=n;k++)
			{
				for(int h=1;h<=m;h++)
				{
					if(ds[i][j]==ds[k][h])
					{
						if((i-k)*(i-k)+(j-h)*(j-h)>chang[i][j])
						{
							chang[i][j]=(i-k)*(i-k)+(j-h)*(j-h);
						}

					}

				}
			}
		}
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			printf("%d ",chang[i][j]);
		}
		printf("\n");
	}
	return 0;
}
